1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	};
15	
16	export function nextGeneration(livingCells: Cell[]): Cell[] {
17	  const liveKeys = new Set(livingCells.map(cellKey));
18	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
19	
20	  for (const cell of livingCells) {
21	    for (const neighbor of neighborsOf(cell)) {
22	      const k = cellKey(neighbor);
23	      const entry = neighborCounts.get(k);
24	      if (entry) entry.count++;
25	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
26	    }
27	  }
28	
29	  const result: Cell[] = [];
30	  for (const [k, { cell, count }] of neighborCounts) {
31	    const willBeAlive = count === 3 || (count === 2 && liveKeys.has(k));
32	    if (willBeAlive) result.push(cell);
33	  }
34	  return result;
35	}
